async function run() {
const res = await fileStorageFilesList(apideck, {
serviceId: "salesforce",
filter: {
driveId: "1234",
folderId: "root",
shared: true,
},
sort: {
by: "updated_at",
},
passThrough: {
"search": "San Francisco",
},
fields: "id,updated_at",
});
if (!res.ok) {
throw res.error;
}
const { value: result } = res;
for await (const page of result) {
// Handle the page
console.log(page);
}
}
run();
